class UserSpecs {
    static org.springframework.data.jpa.domain.Specification<User> statusEq(String status) {
        return (root, query, cb) -> status == null ? cb.conjunction() : cb.equal(root.get("status"), status);
    }

    static org.springframework.data.jpa.domain.Specification<User> roleEq(String role) {
        return (root, query, cb) -> role == null ? cb.conjunction() : cb.equal(root.get("role"), role);
    }

    static org.springframework.data.jpa.domain.Specification<User> emailContains(String email) {
        return (root, query, cb) -> email == null ? cb.conjunction() : cb.like(cb.lower(root.get("email")), "%" + email.toLowerCase() + "%");
    }
}

class UserSearchService {
    private final UserRepository repo;

    UserSearchService(UserRepository repo) { this.repo = repo; }

    public org.springframework.data.domain.Page<User> search(String status, String role, String email, org.springframework.data.domain.Pageable pageable) {
        var spec = UserSpecs.statusEq(status).and(UserSpecs.roleEq(role)).and(UserSpecs.emailContains(email));
        return repo.findAll(spec, pageable);
    }
}

// Ek ogretici ornek
public class UserSpecs {
    public static org.springframework.data.jpa.domain.Specification<User> hasStatus(String status) {
        return (root, query, cb) -> status == null ? cb.conjunction() : cb.equal(root.get("status"), status);
    }
}
